Pattern.Snippet:
```typescript
// explore.session.ts — throwaway exploration script, NOT committed as a test.
import { chromium } from 'playwright';

const browser = await chromium.launch();
const context = await browser.newContext();
const page = await context.newPage();

// 1. Explore
await page.goto('http://localhost:5173/checkout');
console.log(await page.getByRole('region', { name: 'Checkout' }).ariaSnapshot());

// 2. Interact
await page.getByRole('textbox', { name: 'Email' }).fill('user@test.com');
await page.getByRole('button', { name: 'Place Order' }).click();

// 3. Verify — snapshot after interaction; compare delta against intent
console.log(await page.getByRole('region', { name: 'Checkout' }).ariaSnapshot());

// 4. Capture — final snapshot is the seed for the committed test's toMatchAriaSnapshot
await browser.close();
```
